{
  "family": "Pfitzner-Moffatt Oxidation",
  "candidate": {
    "substrate_smiles": [
      "CCCCCO"
    ],
    "product_smiles": [
      "CCCCC=O"
    ],
    "optional_reagent_smiles": [
      "CS(C)=O",
      "C1CCN(CC1)C(=N)C2CCCCN2"
    ],
    "rationale": "This reaction shows the oxidation of a simple primary alcohol (1-pentanol) to the corresponding aldehyde (pentanal) using dimethyl sulfoxide (DMSO) and a carbodiimide (dicyclohexylcarbodiimide, DCC) as the activator, which are the defining reagents for the Pfitzner-Moffatt oxidation. The substrate is a simple, acyclic primary alcohol, representing a clear and fundamental example of this transformation.",
    "collision_avoidance_note": "The use of a simple aliphatic alcohol and the explicit inclusion of DMSO and a carbodiimide (DCC) as reagents clearly defines this as a Pfitzner-Moffatt oxidation. This avoids collision with other named oxidations (e.g., Swern, Corey-Kim) which use different DMSO activators (oxalyl chloride, NCS respectively), or with oxidations using different reagents entirely (e.g., PCC, Dess-Martin)."
  }
}
